<?php
$emergencyId=!empty($MenuName)?(int)$MenuName:0;
$header=$pdo->prepare("SELECT er.*,p.name AS project_name,s.name AS store_name,r.name_en AS receiver_name,ref.name_en AS reference_name,c.name_en AS creator_name,rs.name_en AS receiver_signer_name,rfs.name_en AS reference_signer_name FROM emergency_request er INNER JOIN project_information p ON p.id=er.project_id INNER JOIN store_information s ON s.id=er.store_id INNER JOIN employee_information r ON r.id=er.receiver_id INNER JOIN employee_information ref ON ref.id=er.reference_id LEFT JOIN employee_information c ON c.id=er.created_by LEFT JOIN employee_information rs ON rs.id=er.receiver_signed_by LEFT JOIN employee_information rfs ON rfs.id=er.reference_signed_by WHERE er.id=:id AND er.deleted_at IS NULL");$header->execute(array(':id'=>$emergencyId));$request=$header->fetch();
if(!$request){echo '<div class="alert alert-warning">Emergency request not found.</div>';return;}
$pdo->prepare("UPDATE emergency_request_notification SET read_at=COALESCE(read_at,NOW()) WHERE emergency_request_id=:id AND recipient_id=:user_id")->execute(array(':id'=>$emergencyId,':user_id'=>$LoginReGiSterSession));
$details=$pdo->prepare("SELECT d.*,p.name AS product_name,p.code,p.unit,m.stock_before,m.stock_after FROM emergency_request_detail d INNER JOIN product_information p ON p.id=d.product_id LEFT JOIN emergency_stock_movement m ON m.emergency_request_detail_id=d.id WHERE d.emergency_request_id=:id ORDER BY d.id");$details->execute(array(':id'=>$emergencyId));
$reconciliationStatement=$pdo->prepare("SELECT DISTINCT emergency_request_reconciliation.requestion_invoice_id FROM emergency_request_reconciliation INNER JOIN emergency_request_detail ON emergency_request_detail.id=emergency_request_reconciliation.emergency_request_detail_id WHERE emergency_request_detail.emergency_request_id=:id ORDER BY emergency_request_reconciliation.id");
$reconciliationStatement->execute(array(':id'=>$emergencyId));
$requisitionLinks=$reconciliationStatement->fetchAll();
$emergencyStatusLabels=array('receiver_pending'=>'Waiting for Receiver','reference_pending'=>'Waiting for Reference','completed'=>'Ready for Requisition','reconciled'=>'Finalized in Requisition','finalized'=>'Finalized in Requisition');
$emergencyStatusLabel=isset($emergencyStatusLabels[$request['status']])?$emergencyStatusLabels[$request['status']]:ucwords(str_replace('_',' ',$request['status']));
?>
<style>.emergency-detail-head{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;padding:16px;background:#f8fafc;border:1px solid #dbe4ec;border-radius:8px}.detail-label{font-size:11px;text-transform:uppercase;color:#64748b;font-weight:800}.detail-value{display:block;margin-top:4px;color:#172033;font-weight:700}.sign-flow{display:grid;grid-template-columns:1fr 1fr;gap:14px}.sign-box{border:1px solid #dbe4ec;border-radius:8px;padding:15px;min-height:120px}.sign-box.done{border-color:#86efac;background:#f0fdf4}.sign-state{font-size:12px;color:#64748b}.sign-name{font-weight:800;color:#172033;margin-top:24px}.audit-note{padding:12px 14px;border-left:4px solid #0891b2;background:#ecfeff;color:#164e63}@media(max-width:767px){.emergency-detail-head,.sign-flow{grid-template-columns:1fr}}</style>
<section class="content"><div class="card"><div class="card-header"><h3 class="card-title">Emergency Request <?php echo htmlspecialchars($request['request_no']); ?></h3><div class="card-tools"><a href="?Emergency_Request" class="btn btn-warning"><i class="fas fa-arrow-left"></i> Back</a></div></div><div class="card-body"><div class="emergency-detail-head"><div><span class="detail-label">Issue Date</span><span class="detail-value"><?php echo date('d-m-Y',strtotime($request['date'])); ?></span></div><div><span class="detail-label">Project</span><span class="detail-value"><?php echo htmlspecialchars($request['project_name']); ?></span></div><div><span class="detail-label">Store</span><span class="detail-value"><?php echo htmlspecialchars($request['store_name']); ?></span></div><div><span class="detail-label">Created By</span><span class="detail-value"><?php echo htmlspecialchars($request['creator_name']); ?></span></div><div><span class="detail-label">Status</span><span class="detail-value"><?php echo htmlspecialchars($emergencyStatusLabel); ?></span></div></div><div class="audit-note mt-3"><strong>Emergency reason:</strong> <?php echo nl2br(htmlspecialchars($request['reason'])); ?><?php if($requisitionLinks){ ?><br><strong>Finalized in:</strong> <?php foreach($requisitionLinks as $index=>$requisitionLink){ if($index>0){echo ', ';} ?><a href="?Requestion_History_Detail/<?php echo urlencode($requisitionLink['requestion_invoice_id']); ?>">Requisition <?php echo htmlspecialchars($requisitionLink['requestion_invoice_id']); ?></a><?php } ?><?php } ?></div><div class="table-responsive mt-3"><table class="table table-bordered"><thead><tr><th>Product</th><th>Code</th><th>Unit</th><th>Issued Qty</th><th>Reconciled</th><th>Outstanding</th><th>Stock Before</th><th>Stock After</th><th>Note</th></tr></thead><tbody><?php while($item=$details->fetch()){ ?><tr><td><?php echo htmlspecialchars($item['product_name']); ?></td><td><?php echo htmlspecialchars($item['code']); ?></td><td><?php echo htmlspecialchars($item['unit']); ?></td><td><?php echo $item['issued_quantity']; ?></td><td><?php echo $item['reconciled_quantity']; ?></td><td><?php echo number_format($item['issued_quantity']-$item['reconciled_quantity'],4,'.',''); ?></td><td><?php echo $item['stock_before']; ?></td><td><?php echo $item['stock_after']; ?></td><td><?php echo htmlspecialchars($item['note']); ?></td></tr><?php } ?></tbody></table></div><h5 class="mt-4 mb-3">Acknowledgements</h5><div class="sign-flow"><div class="sign-box <?php echo $request['receiver_signed_at']?'done':''; ?>"><span class="sign-state">1. Material Receiver</span><div class="sign-name"><?php echo htmlspecialchars($request['receiver_name']); ?></div><?php if($request['receiver_signed_at']){ ?><small><i class="fas fa-check-circle text-success"></i> Signed <?php echo date('d-m-Y h:i A',strtotime($request['receiver_signed_at'])); ?></small><?php }elseif((int)$request['receiver_id']===(int)$LoginReGiSterSession){ ?><form method="post" action="?Emergency_Request_Detail/<?php echo $emergencyId; ?>" class="mt-3"><input type="hidden" name="emergency_request_id" value="<?php echo $emergencyId; ?>"><button class="btn btn-success btn-sm" name="Emergency_Request_Acknowledge"><i class="fas fa-signature"></i> Acknowledge Receipt</button></form><?php }else{ ?><small class="text-warning">Waiting for receiver</small><?php } ?></div><div class="sign-box <?php echo $request['reference_signed_at']?'done':''; ?>"><span class="sign-state">2. Reference Person</span><div class="sign-name"><?php echo htmlspecialchars($request['reference_name']); ?></div><?php if($request['reference_signed_at']){ ?><small><i class="fas fa-check-circle text-success"></i> Signed <?php echo date('d-m-Y h:i A',strtotime($request['reference_signed_at'])); ?></small><?php }elseif($request['status']==='reference_pending'&&(int)$request['reference_id']===(int)$LoginReGiSterSession){ ?><form method="post" action="?Emergency_Request_Detail/<?php echo $emergencyId; ?>" class="mt-3"><input type="hidden" name="emergency_request_id" value="<?php echo $emergencyId; ?>"><button class="btn btn-success btn-sm" name="Emergency_Request_Acknowledge"><i class="fas fa-signature"></i> Confirm Reference</button></form><?php }else{ ?><small class="text-muted">Available after receiver acknowledgement</small><?php } ?></div></div></div></div></section>
